#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
ll dp[N],c[N],d[N],n,s;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	for(int i=1;i<=4;i++) cin>>c[i];
	cin>>n;
	dp[0]=1;
	for(int i=1;i<=4;i++)
	{
		for(int j=c[i];j<=N-5;j++) dp[j]+=dp[j-c[i]];
	}
	while(n--)
	{
		ll ans=0;
		for(int i=1;i<=4;i++) cin>>d[i];
		cin>>s;
		for(int i=0;i<(1<<4);i++)
		{
			bool flag=1;
			ll tmp=0;
			for(int j=1;j<=4;j++)
			{
				if(i&(1<<(j-1)))
				{
					tmp+=(c[j]*(d[j]+1));
					flag=!flag;
				}
			}
			if(tmp>s) continue;
			if(flag) ans+=dp[s-tmp];
			else ans-=dp[s-tmp];
		}
		cout<<ans<<"\n";
	}
	return 0;
}
